import { useState, useEffect, useCallback } from "react";
import { useAuth } from "../App";
import Sidebar from "../components/Sidebar";
import { apiStats, apiSimulate, apiPredict, apiHourlyReport, apiZones } from "../utils/api";
import { LineChart, Line, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from "recharts";

export default function Dashboard() {
  const { token } = useAuth();
  const [stats,    setStats]    = useState(null);
  const [hourly,   setHourly]   = useState([]);
  const [predict,  setPredict]  = useState(null);
  const [loading,  setLoading]  = useState(true);
  const [simulating, setSimulating] = useState(false);

  const load = useCallback(async () => {
    try {
      const [s, h, p] = await Promise.all([
        apiStats(token),
        apiHourlyReport(token),
        apiPredict(token).catch(() => null),
      ]);
      setStats(s);
      setHourly(h.report);
      setPredict(p);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, [token]);

  useEffect(() => { load(); }, [load]);

  const simulate = async () => {
    setSimulating(true);
    try {
      await apiSimulate(token);
      await load();
    } finally {
      setSimulating(false);
    }
  };

  if (loading) return (
    <div style={s.layout}>
      <Sidebar />
      <main style={s.main}><div style={s.loading}>Loading dashboard…</div></main>
    </div>
  );

  const statCards = [
    { label: "Total Usage (24h)",   value: `${stats?.total_usage_kwh ?? 0} kWh`, icon: "⚡", color: "#38bdf8" },
    { label: "Peak Load",           value: `${stats?.peak_load_kwh ?? 0} kWh`,   icon: "📈", color: "#fb923c" },
    { label: "Active Alerts",       value: stats?.active_alerts ?? 0,             icon: "🔔", color: "#f87171" },
    { label: "Auto Actions (24h)",  value: stats?.auto_actions ?? 0,              icon: "🤖", color: "#4ade80" },
  ];

  return (
    <div style={s.layout}>
      <Sidebar />
      <main style={s.main}>
        <div style={s.topBar}>
          <div>
            <h1 style={s.pageTitle}>Dashboard</h1>
            <p style={s.pageSub}>Intelligent Energy Management System — Live Overview</p>
          </div>
          <button onClick={simulate} style={s.simBtn} disabled={simulating}>
            {simulating ? "⏳ Simulating…" : "▶ Run Simulation"}
          </button>
        </div>

        {/* Stat Cards */}
        <div style={s.cardRow}>
          {statCards.map(c => (
            <div key={c.label} style={s.statCard}>
              <div style={{ ...s.statIcon, color: c.color }}>{c.icon}</div>
              <div style={{ ...s.statValue, color: c.color }}>{c.value}</div>
              <div style={s.statLabel}>{c.label}</div>
            </div>
          ))}
        </div>

        {/* Hourly Chart */}
        <div style={s.chartBox}>
          <h2 style={s.sectionTitle}>Hourly Energy Consumption (Last 24h)</h2>
          <ResponsiveContainer width="100%" height={260}>
            <BarChart data={hourly} margin={{ top: 5, right: 20, left: 0, bottom: 5 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" />
              <XAxis dataKey="hour" stroke="#64748b" tick={{ fontSize: 11 }} />
              <YAxis stroke="#64748b" tick={{ fontSize: 11 }} unit=" kWh" />
              <Tooltip contentStyle={{ background: "#0f172a", border: "1px solid #334155", color: "#e2e8f0" }} />
              <Bar dataKey="total_kwh" name="Consumption (kWh)" fill="#38bdf8" radius={[4,4,0,0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Zone Breakdown */}
        {stats?.zone_stats && (
          <div style={s.chartBox}>
            <h2 style={s.sectionTitle}>Energy by Zone (24h)</h2>
            <ResponsiveContainer width="100%" height={220}>
              <BarChart data={stats.zone_stats} layout="vertical" margin={{ left: 20 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" />
                <XAxis type="number" stroke="#64748b" tick={{ fontSize: 11 }} unit=" kWh" />
                <YAxis type="category" dataKey="zone" stroke="#64748b" tick={{ fontSize: 11 }} width={90} />
                <Tooltip contentStyle={{ background: "#0f172a", border: "1px solid #334155", color: "#e2e8f0" }} />
                <Bar dataKey="total_kwh" name="Total kWh" fill="#818cf8" radius={[0,4,4,0]} />
                <Bar dataKey="peak_kwh"  name="Peak kWh"  fill="#fb923c" radius={[0,4,4,0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        )}

        {/* Prediction */}
        {predict && !predict.error && (
          <div style={s.predictBox}>
            <h2 style={s.sectionTitle}>📈 AI Prediction — Next Month</h2>
            <div style={s.predictGrid}>
              <div style={s.predictCard}>
                <div style={s.predictValue}>{predict.predicted_kwh_next_month} kWh</div>
                <div style={s.predictLabel}>Predicted Consumption</div>
              </div>
              <div style={s.predictCard}>
                <div style={{ ...s.predictValue, color: "#4ade80" }}>
                  KES {predict.estimated_cost_kes?.toLocaleString()}
                </div>
                <div style={s.predictLabel}>Estimated Cost</div>
              </div>
              <div style={s.predictCard}>
                <div style={{ ...s.predictValue, color: "#fb923c" }}>
                  {(predict.model?.r_squared * 100).toFixed(1)}%
                </div>
                <div style={s.predictLabel}>Model Accuracy (R²)</div>
              </div>
            </div>
            <p style={s.predictNote}>
              Based on Linear Regression model trained on {predict.model?.data_points} daily readings.
              Rate: KES {predict.rate_kes_per_kwh}/kWh.
            </p>
          </div>
        )}
      </main>
    </div>
  );
}

